### Select Statement

`select` lets a goroutine wait on multiple channel operations.

### Basic Select

```go
func main() {
    ch1 := make(chan string)
    ch2 := make(chan string)

    go func() {
        time.Sleep(1 * time.Second)
        ch1 <- "one"
    }()
    go func() {
        time.Sleep(2 * time.Second)
        ch2 <- "two"
    }()

    select {
    case msg1 := <-ch1:
        fmt.Println("Received from ch1:", msg1)
    case msg2 := <-ch2:
        fmt.Println("Received from ch2:", msg2)
    }
}
```

### Select with Default

The `default` case runs immediately if no channels are ready:

```go
select {
case msg := <-ch:
    fmt.Println("Received:", msg)
default:
    fmt.Println("No messages ready")
}
```

### Non-blocking Send

```go
select {
case ch <- msg:
    fmt.Println("Sent message")
default:
    fmt.Println("Channel full, message dropped")
}
```

### Timeout with Select

```go
select {
case result := <-ch:
    fmt.Println(result)
case <-time.After(2 * time.Second):
    fmt.Println("Timeout after 2s")
}
```

### Select with Empty Channels

A nil channel is never ready, useful for disabling cases:

```go
func main() {
    ch1 := make(chan int)
    var ch2 chan int // nil

    go func() {
        ch1 <- 42
    }()

    select {
    case v := <-ch1:
        fmt.Println("from ch1:", v)
    case v := <-ch2: // never selected
        fmt.Println("from ch2:", v)
    }
}
```

### Select Loop

```go
for {
    select {
    case v, ok := <-ch1:
        if !ok {
            ch1 = nil // disable this case
        } else {
            fmt.Println("ch1:", v)
        }
    case v, ok := <-ch2:
        if !ok {
            ch2 = nil
        } else {
            fmt.Println("ch2:", v)
        }
    }
    if ch1 == nil && ch2 == nil {
        break
    }
}
```

> **Key Point:** `select` chooses randomly when multiple channels are ready. The `default` case makes the select non-blocking.

codeExample:
package main

import (
    "fmt"
    "time"
)

func main() {
    ch := make(chan int, 1)

    // Timeout pattern
    select {
    case msg := <-ch:
        fmt.Println("Received:", msg)
    case <-time.After(1 * time.Second):
        fmt.Println("Timeout")
    }

    // Non-blocking send
    msg := "hello"
    strCh := make(chan string, 1)
    strCh <- msg

    select {
    case strCh <- "world":
        fmt.Println("Sent world")
    default:
        fmt.Println("Channel full")
    }
}
